const cv = $input.first().json.data;

function toArray(value) {
  if (Array.isArray(value)) return value;
  if (typeof value === 'string') {
    try {
      const parsed = JSON.parse(value);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      return [];
    }
  }
  return [];
}

const experiences = toArray(cv.experiences);
const education = toArray(cv.education);
const skills = toArray(cv.skills);
const languages = toArray(cv.languages);
const links = toArray(cv.links);

const experienceRows = experiences.map(exp => ({
  role: exp.role || '',
  company: exp.company || '',
  dates: exp.dates || '',
  bullets: Array.isArray(exp.bullets) ? exp.bullets.join(' | ') : (exp.bullets || ''),
  skills: Array.isArray(exp.skills) ? exp.skills.join(', ') : (exp.skills || '')
}));

const educationRows = education.map(ed => ({
  degree: ed.degree || '',
  institution: ed.institution || '',
  dates: ed.dates || '',
  details: ed.details || ''
}));

const skillRows = skills.map(s => ({ skill: typeof s === 'string' ? s : (s.skill || s.name || '') }));

const summaryRow = {
  full_name: cv.full_name || '',
  email: cv.email || '',
  linkedin_url: cv.linkedin_url || '',
  location: cv.location || '',
  summary: cv.summary || '',
  languages: languages.map(l => `${l.language || ''} (${l.proficiency || ''})`).join(', '),
  links: links.map(l => `${l.label || ''}: ${l.url || ''}`).join(' | ')
};

return [{
  json: {
    experienceRows,
    educationRows,
    skillRows,
    summaryRow,
    counts: {
      experiences: experienceRows.length,
      education: educationRows.length,
      skills: skillRows.length
    }
  }
}];
